(function(g){'use strict';class P{constructor(){this.ready=true;this.init()}init(){console.log('PYTML: Ready!');this.processPage()}runPython(c,i={}){try{let o='';let v='';for(const[k,val]of Object.entries(i)){if(typeof val==='string'){v+=`var ${k}="${val.replace(/"/g,'\\"')}";\n`}else if(typeof val==='number'){v+=`var ${k}=${val};\n`}else{v+=`var ${k}=${JSON.stringify(val)};\n`}}let js=v;const l=c.split('\n');for(let line of l){line=line.trim();if(!line)continue;if(line.startsWith('print(')&&line.endsWith(')')){let content=line.slice(6,-1);js+=`o+=${content}+'\\n';\n`}else if(line.startsWith('if ')){let cond=line.slice(3,-1);js+=`if(${cond}){\n`}else if(line.startsWith('elif ')){let cond=line.slice(5,-1);js+=`}else if(${cond}){\n`}else if(line==='else:'){js+=`}else{\n`}else if(line.includes('=')){js+=line+';\n'}}const e=new Function('o',js+'return o;');o=e(o);return o||'No output'}catch(e){return`Error: ${e.message}`}}collectInputs(e){const i={};const f=e.closest('[data-python-form]');if(f){const a=f.querySelectorAll('input, select, textarea');for(const el of a){if(el.name){let v=el.value;if(el.type==='number'){v=parseFloat(v)}i[el.name]=v}}}return i}processPage(){const t=document.querySelectorAll('[data-python-text]');for(const e of t){const c=e.getAttribute('data-python-text');const r=this.runPython(`print(${c})`);if(e)e.textContent=r.trim()}const b=document.querySelectorAll('[data-python]');for(const btn of b){const c=btn.getAttribute('data-python');const t=btn.getAttribute('data-target');btn.addEventListener('click',()=>{const i=this.collectInputs(btn);const r=this.runPython(c,i);if(t){const te=document.querySelector(t);if(te){te.textContent=r}}})}}}const p=new P;g.pytml=p})(window);
